VALUES
  ('social-worker-moex-06900', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '林社工師想瞭解精神病人出院後的生活安排，他以民國101年6月底我國北、中、南地區精神病出院病 人為對象，比較其差異。請問他運用下列那一種方式？', '["橫斷式研究（cross-sectional study）", "縱貫式研究（longitudinal study）", "趨向研究（trend study）", "固定樣本研究（panel study）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06901', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '社會指標（social indicator）也是一種需求評估，運用現有統計資料去反映整體母群體的情況，請問下列 那一項敘述正確？', '["嬰兒死亡率不是做為社區有產前服務需求的指標", "中輟生比率則可以反映僱用學校社會工作人員的需求", "無法反映社會總體統計資料", "無法反映未來的服務型態"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06902', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '自變項為單親爸爸或單親媽媽，依變項為社會排除程度，請問適合進行何種統計分析？', '["卡方分析", "無母數檢定", "t檢定", "相關分析"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06903', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '次級分析（secondary analysis）也是一種研究類型，是將某個研究者所蒐集與處理的資料，再由另一個研 究者重新加以分析。請問下列那一項敘述正確？', '["政府機關才能提供可用的資料", "研究成本便宜", "過期的資料就不能用", "統計資料沒有信度與效度的問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06904', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', 'A組：O1  Xa   O2 B組：O1  Xb  O2 C組：O1    O2 X是介入方案；a是老照片分享；b是種植花草 針對以上研究設計，下列的敘述何者正確？', '["一項研究只可以有一組實驗組", "A組是實驗組，B組和C組是控制組", "Xb是控制組", "Xa是實驗組"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06905', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '「因果關係」的條件相當嚴謹，有3項特定標準，請問不包括下列那一項？', '["兩變項的因果關係時間次序，因在果之前", "因果關係中兩個變項的相關性是可以證實的", "兩個變項的實證關係，是因為第三個變項影響才產生因果關聯", "兩個變項的實證關係，不能因第三個變項影響才產生因果關聯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06906', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '許多學者和實務工作者，目前都普遍重視「以證據為基礎的實務」（evidence-based practice），有關此項 論述，下列那一項說明錯誤？', '["最佳證據支持的處遇方法，因此對每個案主或情況都有效", "實務工作者會依據現有最佳的研究證據做為實務策略或方法", "須認知證據基礎知識的可替換性，因為它會被更新，被更好的研究反駁", "包括批判性的思考、質疑、辨別沒有事實根據的信念和假設"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06907', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '社會科學中常有很多偽科學（pseudoscience）的情形，請問下列那一項不是偽科學？', '["依據權威名師的宣傳", "提出反對事證", "流行的處遇方法", "引述支持者的意見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06908', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '實務社工師會謹慎評估找到的相關研究，決定那一種證據基礎的處遇方式最適合你的特定案主。你正在 進行單親家庭的培力方案，那麼下列那一項對你的幫助最小？', '["受虐婦女援助團體", "弱勢家庭輔導", "親子關係", "就業輔導"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06909', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '科學化的社會工作研究方法包含有嚴謹的思考，但也常發現很多謬論，如過度概推（overgeneralization）、 選擇性觀察（selective observation）等。如果陳社工師運用甲方法輔導吸毒個案小強，效果很好；因此陳 社工師接續對 3 位吸毒個案小鎮、小靜、小安，提供甲方法輔導，結果只有小安有效果，小鎮、小靜都 沒有輔導效果。但是陳社工師不斷對外界說明甲輔導方法多麼好，並強調小強與小安的輔導效果，完全 不注意小鎮、小靜的輔導情形。請問陳社工師犯了下列什麼錯誤？', '["過度概推", "選擇性觀察", "過度概推和選擇性觀察", "過度概推和非選擇性觀察"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
